<?php namespace App\Repositories\Assessment;use App\Repositories\BaseRepository;use App\Models\Assessment\ExamResult;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class ExamResultRepository extends BaseRepository{    public function __construct(ExamResult $model)    {        $this->model = $model;        parent::__construct($model);    }    public function getByExam(int $examId): Collection    {        return $this->findByField('exam_id', $examId);    }    public function getByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function getRankings(int $examId): Collection    {        return $this->query()->selectRaw('student_id, SUM(marks_obtained) as total_marks, SUM(total_marks) as grand_total, AVG(percentage) as avg_percentage')->where('exam_id', $examId)->groupBy('student_id')->orderBy('total_marks', 'desc')->get();    }    public function getByExamAndStudent(int $examId, int $studentId): Collection    {        return $this->query()->where('exam_id', $examId)->where('student_id', $studentId)->get();    }    public function getBySubject(int $subjectId): Collection    {        return $this->findByField('subject_id', $subjectId);    }    public function getPassedResults(int $examId): Collection    {        return $this->query()->where('exam_id', $examId)->where('status', 'passed')->get();    }    public function getFailedResults(int $examId): Collection    {        return $this->query()->where('exam_id', $examId)->where('status', 'failed')->get();    }    public function getByPercentageRange(int $examId, float $min, float $max): Collection    {        return $this->query()->where('exam_id', $examId)->whereBetween('percentage', [$min, $max])->get();    }    public function getStudentPerformanceSummary(int $studentId, int $academicYearId): array    {        $results = $this->query()->where('student_id', $studentId)->whereHas('exam', function ($q) use ($academicYearId) {                $q->where('academic_year_id', $academicYearId);            })->get();        return [            'total_exams' => $results->groupBy('exam_id')->count(),            'total_subjects' => $results->count(),            'average_percentage' => $results->avg('percentage'),            'highest_percentage' => $results->max('percentage'),            'passed_subjects' => $results->where('status', 'passed')->count(),            'failed_subjects' => $results->where('status', 'failed')->count(),        ];    }    public function bulkInsertResults(array $results): bool    {        return $this->bulkInsert($results);    }    public function getClassRankings(int $examId, int $classId): Collection    {        return $this->query()->selectRaw('student_id, SUM(marks_obtained) as total_marks')->where('exam_id', $examId)->whereHas('student', function ($q) use ($classId) {                $q->where('class_id', $classId);            })->groupBy('student_id')->orderBy('total_marks', 'desc')->get();    }}